// Combined Normalize + Code5
// Responsibility:
// 1. Read GLOBAL fields from Webhook ONCE
// 2. Normalize extracted rows
// 3. Aggregate per-topic counts (easy / medium / hard)
// 4. Output ONE item per topic

const items = $input.all();

/* --------------------------------------------------
   STEP 1: Read GLOBAL values from Webhook
-------------------------------------------------- */
let webhookBody = {};
try {
  webhookBody = $('Webhook').first().json.body || {};
} catch (e) {}

const GLOBAL_SKILL =
  webhookBody.skillName ||
  webhookBody.SkillName ||
  '';

const GLOBAL_EMAIL =
  webhookBody.email ||
  webhookBody.Email ||
  '';

const GLOBAL_QTYPE =
  webhookBody.questionType ||
  webhookBody.QuestionType ||
  '';

if (!GLOBAL_SKILL) {
  throw new Error("Combined Node: skill missing from webhook");
}

/* --------------------------------------------------
   Helper: find key ignoring case & spaces
-------------------------------------------------- */
function getKey(obj, target) {
  return Object.keys(obj).find(
    k => k.trim().toLowerCase() === target
  );
}

/* --------------------------------------------------
   STEP 2 + 3: Normalize + Aggregate per topic
-------------------------------------------------- */
const out = [];

for (const item of items) {
  const row = item.json || {};

  const topic =
    row.topic ||
    row.Topic ||
    '';

  if (!topic) continue;

  const context =
    row.context ||
    row.Context ||
    '';

  const easy   = Number(row[getKey(row, 'easy')])   || 0;
  const medium = Number(row[getKey(row, 'medium')]) || 0;
  const hard   = Number(row[getKey(row, 'hard')])   || 0;

  out.push({
    json: {
      skillName: GLOBAL_SKILL,
      topic,
      context,
      email: GLOBAL_EMAIL,
      easy,
      medium,
      hard
    }
  });
}

return out;

/********************
 * CONFIG / CONSTANTS
 ********************/
const FIELD_ORDER_PIPE = [
  "Question Type",
  "Difficulty Level",
  "Question Text",
  "Option (A)",
  "Option (B)",
  "Option (C)",
  "Option (D)",
  "Option (E)",
  "Correct Option (A/B/C/D)",
  "Answer Explanation",
  "Score",
  "Sub-Topics",
  "Author",
  "Topic",
];

// Regex helpers
const RE_FIELD_LINE = /^([^:]+)\s*:\s*(.*)$/;                   // key: value
const RE_OPT_FIELD   = /^Option KATEX_INLINE_OPEN([A-E])KATEX_INLINE_CLOSE/i;
const RE_CORRECT     = /^Correct Option/i;

/****************************************
 * TOPIC FALLBACK (fixed to return Topic)
 ****************************************/
function getTopicWithFallback() {
  let topicValue = null;

  const tryNode = (name) => {
    try {
      const data = $(name).first().json;
      if (data && data.Topic !== undefined) return data.Topic;
    } catch (_) {}
    return null;
  };

  topicValue = tryNode('Code3') || tryNode('Code1') || tryNode('Code4');
  return topicValue || "";
}

/****************************************
 * PARSERS
 ****************************************/

// Normalize key to match our canonical keys (case/spacing tolerant)
function normalizeKeyToKnown(fieldNameRaw, knownKeys) {
  const norm = fieldNameRaw
    .replace(/\s+/g, ' ')
    .replace(/:+$/, '')
    .trim()
    .toLowerCase();

  // Direct match
  for (const k of knownKeys) {
    if (k.toLowerCase() === norm) return k;
  }

  // Option keys like "Option (A)" variations
  const optMatch = norm.match(/^option\s*KATEX_INLINE_OPEN([a-e])KATEX_INLINE_CLOSE$/i);
  if (optMatch) {
    const letter = optMatch[1].toUpperCase();
    return `Option (${letter})`;
  }

  // Correct option variants
  if (norm.startsWith('correct option')) return "Correct Option (A/B/C/D)";

  // Difficulty level variants
  if (norm === 'difficulty level') return "Difficulty Level";
  if (norm === 'sub-topics' || norm === 'sub-topics ') return "Sub-Topics";

  return knownKeys.find(k => k.toLowerCase() === norm) || null;
}

// 1) Parse rows like:
// "Question Type: MCQ | Difficulty Level : Easy | Question Text : ... | Option (A) : ... | ..."
// Also supports unlabeled "MCQ | Easy | ..." (fallback)
function parsePipeRow(row) {
  if (typeof row !== 'string') return null;
  if (!row.includes('|')) return null;

  const questionTemplate = {
    "Question Type": "",
    "Difficulty Level": "",
    "Question Text": "",
    "Option (A)": "",
    "Option (B)": "",
    "Option (C)": "",
    "Option (D)": "",
    "Option (E)": "",
    "Correct Option (A/B/C/D)": "",
    "Answer Explanation": "",
    "Score": "",
    "Sub-Topics": "",
    "Author": "",
    "Topic": ""
  };

  const knownKeys = Object.keys(questionTemplate);

  // Attempt labeled "key: value | key: value" parsing
  const segments = row.split('|').map(s => s.trim()).filter(Boolean);
  let labeledDetected = false;
  const qLabeled = { ...questionTemplate };

  for (const seg of segments) {
    const m = seg.match(RE_FIELD_LINE);
    if (!m) continue;
    labeledDetected = true;

    let fieldNameRaw = m[1].trim();
    let value = m[2].trim();

    const mappedKey = normalizeKeyToKnown(fieldNameRaw, knownKeys);
    if (!mappedKey) continue;

    if (/^Correct Option/i.test(mappedKey)) {
      const corr = value.match(/[A-D]/i);
      if (corr) qLabeled["Correct Option (A/B/C/D)"] = corr[0].toUpperCase();
      continue;
    }

    qLabeled[mappedKey] = value;
  }

  // If labeled parse succeeded and we have at least a stem and type, return it
  if (labeledDetected && qLabeled["Question Type"] && qLabeled["Question Text"]) {
    return qLabeled;
  }

  // Fallback: unlabeled pipe format (MCQ | Easy | ... | ...)
  // Rough check: should have enough parts
  let parts = row.split('|').map(p => p.trim());
  if (parts.length < FIELD_ORDER_PIPE.length) return null;

  if (parts.length > FIELD_ORDER_PIPE.length) {
    const fixed = parts.slice(0, FIELD_ORDER_PIPE.length - 1);
    fixed.push(parts.slice(FIELD_ORDER_PIPE.length - 1).join(' | '));
    parts = fixed;
  }

  const q = { ...questionTemplate };
  FIELD_ORDER_PIPE.forEach((key, idx) => {
    q[key] = (parts[idx] || "").trim();
  });

  return q["Question Type"] && q["Question Text"] ? q : null;
}

// 2) Parse "key: value" style blocks (multi-line)
function parseKeyValueBlock(block) {
  const lines = block.split('\n').map(l => l.trim()).filter(Boolean);
  const question = {
    "Question Type": "",
    "Difficulty Level": "",
    "Question Text": "",
    "Option (A)": "",
    "Option (B)": "",
    "Option (C)": "",
    "Option (D)": "",
    "Option (E)": "",
    "Correct Option (A/B/C/D)": "",
    "Answer Explanation": "",
    "Score": "",
    "Sub-Topics": "",
    "Author": "",
    "Topic": ""
  };

  // Also support single-line "key: value | key: value" here
  if (lines.length === 1 && lines[0].includes('|')) {
    const tryPipe = parsePipeRow(lines[0]);
    if (tryPipe) return tryPipe;
  }

  let currentField = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    const match = line.match(RE_FIELD_LINE);
    if (match) {
      const fieldNameRaw = match[1].trim();
      const value = match[2].trim();

      if (RE_OPT_FIELD.test(fieldNameRaw)) {
        const letter = fieldNameRaw.match(/KATEX_INLINE_OPEN([A-E])KATEX_INLINE_CLOSE/i)[1].toUpperCase();
        question[`Option (${letter})`] = value;
        currentField = `Option (${letter})`;
      } else if (RE_CORRECT.test(fieldNameRaw)) {
        const corr = value.match(/[A-D]/i);
        if (corr) question["Correct Option (A/B/C/D)"] = corr[0].toUpperCase();
        currentField = "Correct Option (A/B/C/D)";
      } else {
        const normKey = normalizeKeyToKnown(fieldNameRaw, Object.keys(question));
        if (normKey) {
          question[normKey] = value;
          currentField = normKey;
        } else {
          currentField = null;
        }
      }
    } else if (currentField === "Question Text" || currentField === "Answer Explanation") {
      if (!RE_FIELD_LINE.test(line)) {
        question[currentField] += " " + line;
      } else {
        i--;
        currentField = null;
      }
    }
  }

  Object.keys(question).forEach(k => question[k] = (question[k] || "").trim());
  if (question["Question Text"] && question["Question Type"]) return question;
  return null;
}

// 3) Top-level dispatcher over any text block (handles code fences too)
function parseMCQQuestions(input) {
  // Ensure string
  if (typeof input !== 'string') {
    try { input = JSON.stringify(input); } catch { input = String(input); }
  }

  // Normalize: strip language tags after ```
  input = input.replace(/```(\w+)?\n/g, '```\n');

  // First, try direct pipe-row parsing line by line:
  const lines = input.split('\n').map(l => l.trim()).filter(Boolean);
  const result = [];

  for (const line of lines) {
    const q = parsePipeRow(line);
    if (q) {
      result.push(q);
    }
  }

  if (result.length > 0) return result;

  // Otherwise, fallback to the old block parser split by triple backticks
  const blocks = input.split("```").filter(b => b.trim() !== "");

  for (const blockRaw of blocks) {
    const block = blockRaw.replace(/^markdown\n/i, '').trim();
    const q = parseKeyValueBlock(block);
    if (q) result.push(q);
  }

  // As a last fallback, try parsing the whole input as a block
  if (result.length === 0) {
    const q = parseKeyValueBlock(input);
    if (q) result.push(q);
  }

  return result;
}

/****************************************
 * APPLY TOPIC
 ****************************************/
function applyTopicMapping(questions) {
  const topicValue = getTopicWithFallback();
  return questions.map(q => {
    if (!q.Topic || q.Topic.trim() === "") q.Topic = topicValue;
    return q;
  });
}

/****************************************
 * MAIN EXECUTION
 ****************************************/
function processInputItems(items) {
  const results = [];

  for (const item of items) {
    try {
      let inputData = item.json;

      // If input is an array like [{ output: "..." }, {...}]
      if (Array.isArray(inputData)) {
        for (const elem of inputData) {
          if (typeof elem === 'string') {
            const parsed = parseMCQQuestions(elem);
            results.push(...applyTopicMapping(parsed).map(q => ({ json: q })));
          } else if (elem && typeof elem === 'object') {
            if (typeof elem.output === 'string') {
              const parsed = parseMCQQuestions(elem.output);
              results.push(...applyTopicMapping(parsed).map(q => ({ json: q })));
            } else {
              // Try any string fields within the element
              for (const k of Object.keys(elem)) {
                const v = elem[k];
                if (typeof v === 'string' && (v.includes('Question Type') || v.includes('|'))) {
                  const parsed = parseMCQQuestions(v);
                  if (parsed.length) {
                    results.push(...applyTopicMapping(parsed).map(q => ({ json: q })));
                  }
                }
              }
            }
          }
        }
        continue;
      }

      if (typeof inputData === 'string') {
        const parsed = parseMCQQuestions(inputData);
        results.push(...applyTopicMapping(parsed).map(q => ({ json: q })));
        continue;
      }

      if (inputData && typeof inputData === 'object') {
        let found = false;

        // Common keys
        const probableKeys = Object.keys(inputData);
        for (const key of probableKeys) {
          const val = inputData[key];
          if (typeof val === 'string' && (val.includes('Question Type') || val.includes('|'))) {
            const parsed = parseMCQQuestions(val);
            if (parsed.length) {
              results.push(...applyTopicMapping(parsed).map(q => ({ json: q })));
              found = true;
            }
          }
        }

        if (!found) {
          const parsed = parseMCQQuestions(JSON.stringify(inputData));
          results.push(...applyTopicMapping(parsed).map(q => ({ json: q })));
        }
      }
    } catch (err) {
      console.error(`Error processing item: ${err.message}`);
    }
  }

  return results.length ? results : [{ json: { Error: "No questions could be parsed from the input" } }];
}

const items = $input.all();
return processInputItems(items);

/**

N8N Code Node for processing webhook data and binary files (Current Version)
This code uses the most current n8n syntax for accessing webhook data
and processing binary files.
*/
// Code that runs for each item
const item = items[0]; // Get the first item

// Extract skillName and email from webhook JSON body
// Using the expression syntax as specified in your requirements
const skillName = $('Webhook').first().json.body.skillName;
const email = $('Webhook').first().json.body.email;

// Process binary data
let binaryDataInfo = {
exists: false,
size: 0,
type: null,
fileName: null
};

// Check if binary data exists
if (item.binary && Object.keys(item.binary).length > 0) {
// Get the first binary property key (usually 'data' as mentioned in your requirements)
const binaryPropertyName = Object.keys(item.binary)[0];
const binaryData = item.binary[binaryPropertyName];

binaryDataInfo = {
exists: true,
size: binaryData.size,
type: binaryData.mimeType,
fileName: binaryData.fileName || 'unknown'
};

// Return the processed data with binary
return {
json: {
skillName,
email,
processedAt: new Date().toISOString(),
binaryInfo: binaryDataInfo,
message: "Successfully processed webhook data and binary file"
},
// Pass through the binary data
binary: item.binary
};
}

// If no binary data, return just the JSON
return {
json: {
skillName,
email,
processedAt: new Date().toISOString(),
binaryInfo: binaryDataInfo,
message: "Successfully processed webhook data, but no binary file was found"
}
};

// Code7 – EASY: attach balanced A–D position and pass angle metadata

const positions = ['A', 'B', 'C', 'D'];
const maxSameInRow = 2;

// collect easy blocks
const easyBlocks = $input.all()
  .map(item => item.json.easy)
  .filter(Boolean);

if (easyBlocks.length === 0) {
  console.warn('No easy blocks found');
  return [];
}

// balanced position picker
const history = [];
const count = { A: 0, B: 0, C: 0, D: 0 };

function pickPosition() {
  let allowed = positions.slice();
  if (history.length >= maxSameInRow) {
    const recent = history.slice(-maxSameInRow);
    if (recent.every(p => p === recent[0])) {
      allowed = allowed.filter(p => p !== recent[0]);
    }
  }
  const min = Math.min(...allowed.map(p => count[p]));
  const pool = allowed.filter(p => count[p] === min);
  const pos = pool[Math.floor(Math.random() * pool.length)];
  history.push(pos);
  count[pos]++;
  return pos;
}

// build output
return easyBlocks.map(block => ({
  json: {
    topic: block.topic,
    context: block.context || '',
    angle_label: block.angle_label,
    angle_instruction: block.angle_instruction,
    semantic_focus: block.semantic_focus || '',
    correctPosition: pickPosition()
  }
}));

