// Combined Angle Expander + Aggregator
// Input:
//  - item.json.output (string OR object) from angle agent
// Output:
//  {
//    easy:   [ {...}, {...} ],
//    medium: [ {...} ],
//    hard:   [ {...} ]
//  }

const items = $input.all();

/* --------------------------------------------------
   Helpers
-------------------------------------------------- */
function stripMarkdown(text) {
  if (typeof text !== 'string') return text;
  return text
    .replace(/```json\s*/gi, '')
    .replace(/```/g, '')
    .trim();
}

function safeParse(input) {
  if (!input) return null;
  if (typeof input === 'object') return input;
  try {
    return JSON.parse(stripMarkdown(input));
  } catch {
    throw new Error('Angle Parser: Invalid JSON in agent output');
  }
}

/* --------------------------------------------------
   Aggregated result
-------------------------------------------------- */
const result = {
  easy: [],
  medium: [],
  hard: []
};

/* --------------------------------------------------
   Main logic
-------------------------------------------------- */
for (const item of items) {
  const raw = item.json.output ?? item.json;
  const parsed = safeParse(raw);

  if (!parsed || typeof parsed !== 'object') {
    throw new Error('Angle Parser: Parsed object invalid');
  }

  for (const diff of ['easy', 'medium', 'hard']) {
    const arr = parsed[diff];

    if (!Array.isArray(arr)) continue;

    arr.forEach((angleObj, index) => {
      result[diff].push({
        topic: angleObj.topic || '',
        context: angleObj.context || '',
        angle_label: angleObj.angle_label || '',
        angle_instruction: angleObj.angle_instruction || '',
        semantic_focus: angleObj.semantic_focus || '',
        question_index: index
      });
    });
  }
}

/* --------------------------------------------------
   Safety check
-------------------------------------------------- */
if (
  result.easy.length === 0 &&
  result.medium.length === 0 &&
  result.hard.length === 0
) {
  throw new Error('Angle Aggregator: No angles produced — check agent output');
}

return [
  {
    json: result
  }
];
